mapper.select:
SELECT COUNT(*) FROM product


        deleted = 0


        AND status = #{status}


        AND category_id = #{categoryId}


        AND brand = #{brand}


        AND (name LIKE CONCAT('%', #{keyword}, '%') OR brand LIKE CONCAT('%', #{keyword}, '%'))

SELECT p.id, p.name, p.description, p.image, p.brand, p.category_id, p.price, p.specs, p.review_count,
       pc.name as categoryName,
       (SELECT AVG(rating) FROM product_review WHERE product_id = p.id AND deleted = 0) as avgRating
FROM product p
LEFT JOIN product_category pc ON p.category_id = pc.id


        p.deleted = 0


        AND p.status = #{status}


        AND p.category_id = #{categoryId}


        AND p.brand = #{brand}


        AND (p.name LIKE CONCAT('%', #{keyword}, '%') OR p.brand LIKE CONCAT('%', #{keyword}, '%'))


ORDER BY p.create_time DESC
LIMIT #{pageSize} OFFSET #{offset}
